For each ship order, evaluate insertion into existing routes via a regret-based scoring mechanism that considers both immediate cost increase and route compatibility, falling back to new assign creation if necessary, while preserving state during trials.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialResult struct {
		assignIdx  int
		costDelta  float64
		feasible   bool
	}

	orderCount := len(oris)
	if orderCount != len(dess) || orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for orderID := 0; orderID < orderCount; orderID++ {
		ori := oris[orderID]
		des := dess[orderID]
		shipID := total_ship + orderID

		bestFeasible := trialResult{assignIdx: -1, costDelta: 1e18, feasible: false}

		existingAssignLimit := dispatch.AssignsLen
		if existingAssignLimit > MAXASSIGNS {
			existingAssignLimit = MAXASSIGNS
		}

		originalCosts := make([]float64, existingAssignLimit)
		for i := 0; i < existingAssignLimit; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}

		for idx := 0; idx < existingAssignLimit; idx++ {
			prevCost := dispatch.Assigns[idx].Cost

			success := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if !success {
				continue
			}

			dispatch.Assigns[idx].GenRoute()

			newCost := dispatch.Assigns[idx].Cost
			if newCost < 0 {
				dispatch.Assigns[idx].RemoveShip(shipID)
				dispatch.Assigns[idx].GenRoute()
				continue
			}

			delta := newCost - prevCost
			if delta < bestFeasible.costDelta {
				bestFeasible.assignIdx = idx
				bestFeasible.costDelta = delta
				bestFeasible.feasible = true
			}

			dispatch.Assigns[idx].RemoveShip(shipID)
			dispatch.Assigns[idx].GenRoute()
		}

		if bestFeasible.feasible {
			dispatch.Assigns[bestFeasible.assignIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestFeasible.assignIdx].GenRoute()
		} else {
			fallbackCreated := false
			if dispatch.AssignsLen < MAXASSIGNS {
				idxNew := dispatch.AssignsLen
				success := dispatch.Assigns[idxNew].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[idxNew].GenRoute()
					if dispatch.Assigns[idxNew].Cost >= 0 {
						dispatch.AssignsLen++
						fallbackCreated = true
					} else {
						dispatch.Assigns[idxNew].RemoveShip(shipID)
						dispatch.Assigns[idxNew].GenRoute()
					}
				}
			}

			if !fallbackCreated {
				for idxCheck := 0; idxCheck < MAXASSIGNS; idxCheck++ {
					success := dispatch.Assigns[idxCheck].AddShip(shipID, ori, des)
					if success {
						dispatch.Assigns[idxCheck].GenRoute()
						if dispatch.Assigns[idxCheck].Cost >= 0 {
							break
						} else {
							dispatch.Assigns[idxCheck].RemoveShip(shipID)
							dispatch.Assigns[idxCheck].GenRoute()
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

